class Solution(object):
    def lexSmallestNegatedPerm(self, n, target):
        S = n * (n + 1) // 2
        if target < -S or target > S:
            return []
        D = S - target  # total amount to reduce by flipping
        if D % 2 != 0:
            return []
        D //= 2  # sum of values to negate
        # Greedily negate largest values first
        negated = set()
        for x in range(n, 0, -1):
            if D >= x:
                negated.add(x)
                D -= x
        if D != 0:
            return []
        result = []
        for x in range(1, n + 1):
            result.append(-x if x in negated else x)
        result.sort()
        return result
